`).map((f,d)=>{if(f==="")return e.jsx("div",{style:{height:8}},d);const p=f.split(/\*\*(.*?)\*\*/g);return e.jsx("p",{style:{fontSize:13.5,lineHeight:1.75,color:"#3a3a3a",marginBottom:2},children:p.map((m,L)=>L%2===1?e.jsx("strong",{style:{color:"#1a1a1a",fontWeight:600},children:m},L):e.jsx("span",{children:m},L))},d)});return e.jsxs("div",{style:{fontFamily:"'Source Serif 4',Georgia,serif",background:"#F5F3EE",minHeight:r?"auto":"100vh",color:"#1a1a1a"},children:[e.jsx("style",{children:`
